// Extract input data
const input = $json.text || $json.input || $json.prompt;
const model = $json.model || 'gpt-3.5-turbo';
const maxTokens = $json.maxTokens || 150;
const temperature = $json.temperature || 0.7;
const metadata = $json._metadata || {};

console.log('📡 TrustGate Adapter - Processing request');
console.log('Model:', model);
console.log('Input length:', input?.length || 0);

return {
  input,
  model,
  maxTokens,
  temperature,
  metadata
};

// Extract and normalize response from TrustGate (OpenAI-compatible)
const response = $json;
const content = response.choices?.[0]?.message?.content || '';

if (!content || content.length === 0) {
  throw new Error('Empty response from TrustGate');
}

// Calculate hash
const crypto = require('crypto');
const hash = crypto.createHash('sha256').update(content).digest('hex');

// Extract usage data
const usage = response.usage || {};
const inputTokens = usage.prompt_tokens || Math.ceil($node['Prepare Request'].json.input.length / 4);
const outputTokens = usage.completion_tokens || Math.ceil(content.length / 4);
const totalTokens = usage.total_tokens || inputTokens + outputTokens;

// Calculate quality score (simple heuristic)
const qualityScore = Math.min(100, Math.max(0, 
  (content.length > 10 ? 50 : 0) + 
  (content.match(/[.!?]/g)?.length * 5 || 0)
));

console.log('✅ TrustGate Response:', content.substring(0, 50) + '...');
console.log('Tokens:', totalTokens, 'Quality:', qualityScore);

return {
  content,
  hash,
  model: response.model || $node['Prepare Request'].json.model,
  provider: 'trustgate',
  tokens: {
    input: inputTokens,
    output: outputTokens,
    total: totalTokens
  },
  cost: 0,
  qualityScore,
  timestamp: Date.now(),
  metadata: $node['Prepare Request'].json.metadata
};
